module divide_by_8 (  
    input wire clk,  
    input wire rst,  
    output reg out  
);  
    reg [2:0] counter;  // 3-bit counter to counter up to 7 (0-7)  

    always @(posedge clk or posedge rst) begin  
        if (rst) begin  
            counter <= 3'b000;  
            out <= 0;  
        end else if (counter == 3'b111) begin  
            counter <= 3'b000;  
            out <= 1;  
        end else begin  
            counter <= counter + 1;  
            out <= 0;  
        end  
    end  
endmodule
